using namespace std;

class Solution {
public:
    vector<int> findArticulationPoints(int n, vector<vector<int>>& edges) {
        vector<int> result;
        bool isVisiting[n] = {false};
        bool isArticulationPoint[n] = {false};
        vector<int> discoveryTime;
        vector<int> low;

        function<void(int)> dfs = [&](int node) {
            discoveryTime.push_back(node);
            low[node] = node;
            int childCount = 0;

            for (int i = 0; i < edges[node].size(); i++) {
                int adjacentNode = edges[node][i];
                if (!isVisiting[adjacentNode]) {
                    isVisiting[adjacentNode] = true;
                    dfs(adjacentNode);
                    low[node] = min(low[node], low[adjacentNode]);
                    childCount++;
                    if (discoveryTime[node] < low[adjacentNode]) {
                        isArticulationPoint[node] = true;
                    }
                }
                else if (low[adjacentNode] >= discoveryTime[node]) {
                    low[node] = min(low[node], low[adjacentNode]);
                }
            }

            if (node == 0 && childCount > 1) {
                isArticulationPoint[node] = true;
            }
        };

        for (int i = 0; i < n; i++) {
            isVisiting[i] = false;
        }

        dfs(0);

        for (int i = 0; i < n; i++) {
            if (isArticulationPoint[i]) {
                result.push_back(i);
            }
        }

        return result;
    }
};

int main() {
    int n, m;
    cin >> n >> m;
    vector<vector<int>> edges(n);

